#include "interface.h"

uint64_t asof_join_sum(
    const std::vector<uint32_t>& dim_ts,
    const std::vector<uint32_t>& dim_values,
    const std::vector<uint32_t>& probe_ts,
    const std::vector<uint32_t>& probe_weights,
    int iters) {
  uint64_t sum = 0;
  const std::size_t dim_size = dim_ts.size();
  const std::size_t probe_size = probe_ts.size();

  if (dim_size == 0 || probe_size == 0) {
    return 0;
  }

  const uint32_t* dim_ts_ptr = dim_ts.data();
  const uint32_t* dim_val_ptr = dim_values.data();
  const uint32_t* probe_ts_ptr = probe_ts.data();
  const uint32_t* probe_w_ptr = probe_weights.data();
  const uint32_t* dim_end = dim_ts_ptr + dim_size;

  for (int iter = 0; iter < iters; ++iter) {
    sum = 0;
    const uint32_t* cur_dim_ts = dim_ts_ptr;
    const uint32_t* cur_dim_val = dim_val_ptr;
    for (std::size_t i = 0; i < probe_size; ++i) {
      uint32_t p_ts = probe_ts_ptr[i];
      while (cur_dim_ts + 1 < dim_end && *(cur_dim_ts + 1) <= p_ts) {
        ++cur_dim_ts;
        ++cur_dim_val;
      }
      sum += static_cast<uint64_t>(*cur_dim_val) * static_cast<uint64_t>(probe_w_ptr[i]);
    }
  }
  return sum;
}
